<?php $health=is_array($health??null)?$health:[]; $modules=is_array($health['modules']??null)?$health['modules']:[]; $workers=is_array($health['workers']??null)?$health['workers']:[]; ?>
<section class="card"><h1>Platform Health</h1><p>Estado operativo read-only por módulo (tenant actual).</p></section>
<section class="card"><h2>Módulos</h2><table><thead><tr><th>Módulo</th><th>Estado</th><th>Failed</th><th>Warning</th><th>Passed</th><th>Jobs running</th><th>Último check</th></tr></thead><tbody><?php foreach($modules as $m): ?><tr><td><a href="/platform/health/modules/<?= urlencode((string)($m['code']??'')) ?>"><?= htmlspecialchars((string)($m['name']??''),ENT_QUOTES,'UTF-8') ?></a></td><td><?= htmlspecialchars((string)($m['status']??'passed'),ENT_QUOTES,'UTF-8') ?></td><td><?= (int)($m['failed']??0) ?></td><td><?= (int)($m['warning']??0) ?></td><td><?= (int)($m['passed']??0) ?></td><td><?= (int)($m['running_jobs']??0) ?></td><td><?= htmlspecialchars((string)($m['last_run_at']??'N/A'),ENT_QUOTES,'UTF-8') ?></td></tr><?php endforeach; ?></tbody></table></section>
<section class="card"><h2>Workers</h2><ul><?php foreach($workers as $w): ?><li><?= htmlspecialchars((string)($w['status']??'unknown'),ENT_QUOTES,'UTF-8') ?>: <?= (int)($w['total']??0) ?> (heartbeat: <?= htmlspecialchars((string)($w['last_heartbeat_at']??'N/A'),ENT_QUOTES,'UTF-8') ?>)</li><?php endforeach; ?></ul></section>
